info.onScore(10, function () {
    if (level == 3) {
        game.setGameOverMessage(true, "You win!")
        game.gameOver(true)
    } else {
        game.showLongText("Level complete!", DialogLayout.Bottom)
        level = level + 1
        startLevel(level)
    }
})
